INSERT INTO documents (section_slug, page_slug, title, content, updated_by)
VALUES (
  'affiliate',
  'glossary',
  'Glossary',
  $JSON${"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Affiliate Glossary"}]},{"type":"paragraph","content":[{"type":"text","text":"Reference Document. Key terms, commission mechanics, Philippines regulatory definitions, and payment infrastructure references for the Affiliate Management workflow."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Commission & Programme Terms"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"RevShare — Revenue Share"}]},{"type":"paragraph","content":[{"type":"text","text":"A commission model where the affiliate earns a percentage of the net gaming revenue (NGR) generated by their referred players on an ongoing monthly basis. Rates are expressed as a percentage of NGR and vary by affiliate level (L1\u2013L5) and traffic quality tier."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"CPA — Cost Per Acquisition"}]},{"type":"paragraph","content":[{"type":"text","text":"A flat-fee commission paid once per qualifying player — defined as a player who completes KYC and makes a first-time deposit (FTD) above the minimum threshold. CPA is not recurring. If the player never deposits again, no further CPA commission is generated."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"NGR — Net Gaming Revenue"}]},{"type":"paragraph","content":[{"type":"text","text":"The revenue used as the basis for RevShare calculations. Calculated as: player deposits minus player withdrawals minus bonuses paid minus platform operating costs (payment fees, game licensing costs). If NGR is negative in a given month (operator pays out more than it receives), this affects the affiliate's earnings per the negative carryover policy."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"FTD — First-Time Deposit"}]},{"type":"paragraph","content":[{"type":"text","text":"A player's very first deposit after completing KYC registration. The FTD is the trigger event for CPA commission payment. The minimum qualifying FTD amount is defined in the affiliate agreement (standard: \u20b1500). FTDs that are charged back within 30 days do not qualify for CPA."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Negative Carryover — Monthly Negative Balance Policy"}]},{"type":"paragraph","content":[{"type":"text","text":"When a player wins significantly in a given month, the affiliate's NGR for that player goes negative. Under a negative carryover policy, this negative balance is carried forward and deducted from future months' earnings before the affiliate receives any commission. Without negative carryover (monthly reset), the affiliate's balance resets to zero each month regardless of negative outcomes."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Cookie Window — Attribution Tracking Period"}]},{"type":"paragraph","content":[{"type":"text","text":"The period during which a player who clicks an affiliate tracking link will be attributed to that affiliate if they register. Standard: 30 days. Premium partners: up to 90 days. If the cookie expires before the player registers, no attribution is recorded for that affiliate."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Sub-Affiliate — Downstream Network Partner"}]},{"type":"paragraph","content":[{"type":"text","text":"An affiliate recruited into the network by an existing affiliate partner (their upline). Sub-affiliates earn commissions on their own direct player referrals. Their upline earns an override commission on the sub-affiliate's earnings — this is the mechanism that creates the multi-level structure."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Override — Upstream Commission on Downstream Earnings"}]},{"type":"paragraph","content":[{"type":"text","text":"The commission earned by an upline affiliate on the earnings of the affiliates they recruited. For example: an L1 partner earns a 5% override on L2's RevShare commissions. Overrides cascade through all active levels simultaneously in the monthly processing run."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Clawback — Commission Reversal"}]},{"type":"paragraph","content":[{"type":"text","text":"The recovery of commissions already paid when a player's FTD is reversed (chargeback), or when fraud is confirmed in the affiliate's referral activity. Clawback provisions must be explicitly stated in the affiliate agreement and specify the time window within which clawback can be applied (typically up to 6 months)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Last-Click Attribution — Default Attribution Model"}]},{"type":"paragraph","content":[{"type":"text","text":"The affiliate whose tracking link was clicked most recently before a player registered receives 100% of the commission credit for that player. This is the industry default. If a player clicks L1 affiliate A's link on Day 1, then clicks L1 affiliate B's link on Day 3 and registers, affiliate B receives full attribution."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Hybrid — Combined CPA + RevShare"}]},{"type":"paragraph","content":[{"type":"text","text":"A bespoke commission structure offering both a reduced CPA on qualifying FTDs and a reduced RevShare rate on ongoing NGR. Provides the affiliate with immediate income and long-term upside. Hybrid terms must be individually negotiated and require Head of Affiliates approval before being offered."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Cookie Stuffing — Affiliate Fraud Technique"}]},{"type":"paragraph","content":[{"type":"text","text":"A fraudulent technique where an affiliate uses hidden scripts or iframes to drop tracking cookies on users' browsers without those users ever seeing or clicking an affiliate link. Results in false attribution of player registrations. Grounds for immediate termination and full clawback."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Philippines Regulatory Terms"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"CWT — Creditable Withholding Tax (BIR Requirement)"}]},{"type":"paragraph","content":[{"type":"text","text":"BIR tax withheld by the operator from commission payments to individual Filipino affiliates. Rate: 10% (standard professional rate) or 8% (if affiliate has elected the 8% income tax option). The operator remits CWT to BIR on the affiliate's behalf. The affiliate receives BIR Form 2307 as proof of withholding to use as a tax credit in their annual ITR."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"EWT — Expanded Withholding Tax (BIR Requirement)"}]},{"type":"paragraph","content":[{"type":"text","text":"BIR tax withheld from commission payments to corporate affiliate partners (domestic corporations and partnerships). Rate: 2% on commission amounts. Same remittance and Form 2307 requirements apply as for CWT."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"BIR Form 2307 — Certificate of Creditable Tax Withheld (BIR — Quarterly)"}]},{"type":"paragraph","content":[{"type":"text","text":"A BIR document issued by the operator to the affiliate each quarter confirming the amount of withholding tax deducted from their commissions. Affiliates use this form to claim a tax credit against their own income tax liability. Failure to issue Form 2307 is a BIR compliance violation with potential penalties."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"SEC Registration — Securities & Exchange Commission (Corporate Requirement)"}]},{"type":"paragraph","content":[{"type":"text","text":"Corporate affiliates (companies, partnerships) must be registered with the Philippine SEC. SEC registration documents are part of the KYC requirement for corporate affiliate onboarding. The SEC registration number must be included in the affiliate agreement for corporate partners."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"PAGCOR Affiliate Rules — Marketing Compliance Framework (PAGCOR Compliance)"}]},{"type":"paragraph","content":[{"type":"text","text":"PAGCOR imposes specific restrictions on how licensed operators may market through affiliates. Key requirements: no targeting of minors, no advertising near schools or churches, responsible gambling messaging required in all affiliate content, affiliate channel documentation must be available for PAGCOR audit. Non-compliant affiliate activity is the operator's liability under the licence."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"TIN — Tax Identification Number (BIR Mandatory)"}]},{"type":"paragraph","content":[{"type":"text","text":"A unique number issued by the BIR to all taxpayers in the Philippines. Both individual and corporate affiliates must provide a valid TIN before the first commission payment is processed. Commission payments cannot be made to affiliates without a TIN on file — this is an operator obligation, not merely a best practice."}]}]}$JSON$::jsonb,
  'system'
)
ON CONFLICT (section_slug, page_slug) DO UPDATE
  SET title = EXCLUDED.title,
      content = EXCLUDED.content,
      updated_at = NOW(),
      updated_by = EXCLUDED.updated_by;
